namespace sv_f635c525a3a941628c96ac7b60309b0e.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service (one per circuit) that holds the currently selected warehouse
/// and notifies all subscribers when the selection changes.
/// </summary>
public class WarehouseStateService
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A" },
        new() { Id = "WH-B", Name = "Warehouse B" },
        new() { Id = "WH-C", Name = "Warehouse C" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public WarehouseInfo CurrentWarehouse =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId);

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_f635c525a3a941628c96ac7b60309b0e.Services;

/// <summary>
/// Scoped service (one per circuit) that provides low-stock alert counts
/// and broadcasts updates to all subscribed components.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private CancellationTokenSource? _pollCts;
    private int _subscriberCount;

    public int CurrentLowStockCount { get; private set; }

    /// <summary>Fired when new alert data arrives. Subscribers must marshal to UI thread.</summary>
    public event Func<Task>? OnAlertDataChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChanged;
    }

    /// <summary>Simulates a database query — returns a random number 0–15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Increments the subscriber count. Starts polling when the first subscriber registers.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _pollCts = new CancellationTokenSource();
            _ = PollLoopAsync(_pollCts.Token);
        }
    }

    /// <summary>
    /// Decrements the subscriber count. Stops polling when the last subscriber unregisters.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _pollCts?.Cancel();
            _pollCts?.Dispose();
            _pollCts = null;
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                CurrentLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
                await NotifySubscribers();
                await Task.Delay(TimeSpan.FromSeconds(10), ct);
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    private async void HandleWarehouseChanged()
    {
        // Immediately refresh when the warehouse changes.
        try
        {
            CurrentLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
            await NotifySubscribers();
        }
        catch
        {
            // Swallow — component may have been disposed during navigation.
        }
    }

    private async Task NotifySubscribers()
    {
        if (OnAlertDataChanged is not null)
        {
            foreach (var handler in OnAlertDataChanged.GetInvocationList().Cast<Func<Task>>())
            {
                try { await handler(); }
                catch { /* subscriber disposed */ }
            }
        }
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChanged;
        _pollCts?.Cancel();
        _pollCts?.Dispose();
    }
}

