@using sv_f635c525a3a941628c96ac7b60309b0e.Services
@inject WarehouseStateService WarehouseState
@implements IDisposable

<select class="form-select form-select-sm" style="width:auto;"
        value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseStateService.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_f635c525a3a941628c96ac7b60309b0e.Services
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.CurrentLowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.CurrentLowStockCount</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertDataChanged += OnDataChanged;
    }

    private async Task OnDataChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= OnDataChanged;
    }
}

