@page "/dashboard"
@using sv_f635c525a3a941628c96ac7b60309b0e.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 30rem;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouse.Name</h5>
        <p class="card-text">
            Low-stock alerts:
            @if (_lowStockCount.HasValue)
            {
                <span class="badge bg-danger fs-6">@_lowStockCount</span>
            }
            else
            {
                <span class="text-muted">Loading…</span>
            }
        </p>
        <p class="text-muted mb-0" style="font-size: 0.85rem;">
            Refreshes every 10 seconds. Last update: @_lastUpdated?.ToString("T")
        </p>
    </div>
</div>

@code {
    private int? _lowStockCount;
    private DateTime? _lastUpdated;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertDataChanged += OnAlertDataChanged;
        AlertService.StartPolling();
    }

    private async void OnWarehouseChanged()
    {
        // Alert service already refreshes on warehouse change;
        // we just need to re-render once it fires OnAlertDataChanged.
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnAlertDataChanged()
    {
        _lowStockCount = AlertService.CurrentLowStockCount;
        _lastUpdated = DateTime.Now;
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertDataChanged -= OnAlertDataChanged;
        AlertService.StopPolling();
    }
}

